// icon-label.tsx

import type * as React from 'react';

import {cn} from '@/lib/utils';

type IconLabelProps = React.HTMLAttributes<HTMLElement> &
  React.AnchorHTMLAttributes<HTMLAnchorElement> & {
    /** Icon component rendered before the label text */
    icon?: React.ComponentType<React.SVGProps<SVGSVGElement>>;
    /** Icon component rendered after the label text */
    endIcon?: React.ComponentType<React.SVGProps<SVGSVGElement>>;
    /** Additional className applied to both icons */
    iconClassName?: string;
    /** Render as a different element. @default "span" */
    as?: React.ElementType;
  };

function IconLabel({
  icon: Icon,
  endIcon: EndIcon,
  iconClassName,
  className,
  children,
  as: Comp = 'span',
  ...props
}: IconLabelProps) {
  return (
    <Comp
      data-slot="icon-label"
      className={cn('inline-flex items-center gap-1.5', className)}
      {...props}
    >
      {Icon && (
        <Icon
          aria-hidden="true"
          className={cn('size-[1em] shrink-0', iconClassName)}
        />
      )}
      {children}
      {EndIcon && (
        <EndIcon
          aria-hidden="true"
          className={cn('size-[1em] shrink-0', iconClassName)}
        />
      )}
    </Comp>
  );
}

export {IconLabel};
export type {IconLabelProps};
